import React from "react";
import "./test.css";

const typeDescriptions = {
  ENFP: "სხარტი, ენერგიული და ინოვაციური ადამიანი, რომელიც მარტივად ახდენს ურთიერთობებს.",
  ISTJ: "კარგი ორგანიზატორი, დეტალებზე ორიენტირებული და პასუხისმგებელი.",
  INFJ: "კრეატიული, ღრმა და დაფიქრებული.",
  ESFP: "ცოცხალი, მეგობრული და მომხიბვლელი, ხალხთან კომუნიკაციაში.",
  INFP: "ემოციური, ღრმა და გულწრფელი, იდეებით მართულს.",
  ESTJ: "ორგანიზებული, პასუხისმგებლიანი და პრაქტიკული ლიდერი.",
  ENFJ: "ენერგიული, მოტივირებული და სოციალური კავშირების სპეციალისტი.",
  ISFP: "მშვიდი, შემოქმედებითი და ბუნებაზე ორიენტირებული ადამიანი.",
  ISTP: "პრაქტიკული, ანალიტიკური და დამოუკიდებელი.",
  ESFJ: "გულწრფელი, სანდო და მეგობრული კომუნიკატორი.",
  ENTJ: "ლიდერი, სტრატეგი და მიზანმიმართული.",
  INTJ: "სტრატეგიული, დამოუკიდებელი და ნოვატორი.",
  ESTP: "აქტიური, რისკის მსურველი და სწრაფი მოსაზრებების მქონე.",
  ENTP: "ინოვატორი, შემოქმედებითი და მოსაზრებების გენერატორი.",
  ISFJ: "გულწრფელი, მოსიყვარულე და დეტალებზე ორიენტირებული.",
  INFJ: "კრეატიული, ღრმა და დაფიქრებული."
};

export default function FinalResult({ results }) {
  const type =
    (results.EI || "") +
    (results.SN || "") +
    (results.TF || "") +
    (results.JP || "");

  return (
    <div className="test-card">
      <h2 className="test-title">{type}</h2>

      <img
        className="result-image"
        src={`/images/types/${type}.png`}
        alt={type}
      />

      <p className="test-description">
        {typeDescriptions[type] || "ეს არის მოკლე აღწერა თქვენს ფსიქოტიპზე."}
      </p>

      <p>
        მეტი ინფორმაციისთვის გადადით{" "}
        <a href="/articles" style={{ color: "#ffffff", textDecoration: "underline" }}>
          მიმოხილვების
        </a>{" "}
        გვერდზე
      </p>
    </div>
  );
}
